using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Http;
using Microsoft.IdentityModel.Tokens;

public class JwtAuthenticationMiddleware : IMiddleware
{
    private readonly IJwtValidator _jwtValidator;

    public JwtAuthenticationMiddleware(RequestDelegate next, IJwtValidator jwtValidator)
    {
        Next = next;
        _jwtValidator = jwtValidator;
    }

    public RequestDelegate Next { get; }

    public async Task InvokeAsync(HttpContext context)
    {
        string tokenString = null;
        if (context.Request.Headers.TryGetValue("Authorization", out var values))
        {
            tokenString = values.FirstOrDefault()?.ToString();
        }

        if (tokenString != null)
        {
            var jwtSecurityToken = new JwtSecurityToken(tokenString);
            if (_jwtValidator.ValidateToken(jwtSecurityToken))
            {
                context.Items["JWT"] = jwtSecurityToken;
                await Next(context);
            }
            else
            {
                context.Response.StatusCode = 401;
            }
        }
    }
}